import React, { useState, useContext } from 'react';
import { useTranslation } from 'react-i18next';
import { CartContext } from '../context/CartContext';

const MenuCard = ({ item }) => {
  const { language } = useTranslation();
  const { addToCart } = useContext(CartContext);
  const [size, setSize] = useState(item.prices.small ? 'small' : null);
  const [quantity, setQuantity] = useState(1);
  const [notes, setNotes] = useState('');

  const price = size ? item.prices[size] : item.prices || 0;

  const handleAdd = () => {
    addToCart({
      id: item.id,
      name: item.name,
      size,
      quantity,
      notes,
      price,
    });
    setQuantity(1);
    setNotes('');
  };

  return (
    <div className="menu-card">
      <h3>{item.name[language]}</h3>
      <p>{item.description?.[language]}</p>

      {item.prices && item.prices.small && (
        <div className="size-selector">
          <label>
            <input type="radio" name={`${item.id}-size`} value="small" checked={size === 'small'} onChange={() => setSize('small')} />
            {language === 'ar' ? 'صغير' : 'Small'} ({item.prices.small} LE)
          </label>
          <label>
            <input type="radio" name={`${item.id}-size`} value="large" checked={size === 'large'} onChange={() => setSize('large')} />
            {language === 'ar' ? 'كبير' : 'Large'} ({item.prices.large} LE)
          </label>
        </div>
      )}
      {!item.prices.small && <p>{price} LE</p>}

      <div className="quantity-selector">
        <button disabled={quantity <= 1} onClick={() => setQuantity(quantity - 1)}>-</button>
        <span>{quantity}</span>
        <button onClick={() => setQuantity(quantity + 1)}>+</button>
      </div>

      <textarea
        placeholder={language === 'ar' ? 'أضف ملاحظات...' : 'Add notes...'}
        value={notes}
        onChange={(e) => setNotes(e.target.value)}
      />

      <button onClick={handleAdd} className="btn btn-secondary">
        {language === 'ar' ? 'أضف إلى السلة' : 'Add to Cart'}
      </button>
    </div>
  );
};

export default MenuCard;
